import{_ as a,o as t,c as i,a2 as n}from"./chunks/framework.DnrXFDHb.js";const _=JSON.parse('{"title":"F11: 處分重大資產與資本配置 - finance-investment-researcher 審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/6261_久元/20260424/F11_處分重大資產與資本配置_投資研究員.md","filePath":"審計報告庫/財務審計/6261_久元/20260424/F11_處分重大資產與資本配置_投資研究員.md"}'),o={name:"審計報告庫/財務審計/6261_久元/20260424/F11_處分重大資產與資本配置_投資研究員.md"};function r(l,e,d,s,c,h){return t(),i("div",null,[...e[0]||(e[0]=[n('<h1 id="f11-處分重大資產與資本配置-finance-investment-researcher-審計報告" tabindex="-1">F11: 處分重大資產與資本配置 - finance-investment-researcher 審計報告 <a class="header-anchor" href="#f11-處分重大資產與資本配置-finance-investment-researcher-審計報告" aria-label="Permalink to &quot;F11: 處分重大資產與資本配置 - finance-investment-researcher 審計報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><p>是否存在處分重大資產（如土地、專利、子公司）之行為？處分損益佔比為何？資金用途是投入再投資還是為了彌補虧損？</p><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><p>根據截至2025年Q4最新公開數據，久元（6261）於2024年處分重要子公司「廈門久元電子有限公司」股權，屬戰略性收縮中國市場佈局。處分相關損失約729萬元佔淨利0.6%，影響輕微；但資本支出從3.76億暴增至9.83億，顯示資金明確投入台灣本土產能擴張，屬「戰略轉型」而非「祖產求生」。獲利純度判定為中等偏上。</p><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><p><strong>評級：A（良）</strong></p><p>久元2023-2025年營業收入分別為11.75億、9.26億、11.83億；營業利益分別為2.81億、0.56億、1.09億；稅後淨利分別為1.95億、1.22億、1.89億。廈門久元處分案於2024年確認停業單位損益-729萬元，佔全年淨利比重僅0.6%，屬輕微影響。業外損益（OTHNOE）三年分別為2,061萬、1,396萬、1,583萬，佔淨利比分別為1.06%、1.15%、0.84%，業外依賴度極低。資本支出（CapEx）從2023年的3.33億大幅攀升至2024年3.76億、2025年9.83億，資金流向明確指向產能擴充而非償債或彌補虧損。</p><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><h3 id="一、獲利含金量穿透-earnings-purity" tabindex="-1">一、獲利含金量穿透（Earnings Purity） <a class="header-anchor" href="#一、獲利含金量穿透-earnings-purity" aria-label="Permalink to &quot;一、獲利含金量穿透（Earnings Purity）&quot;">​</a></h3><p><strong>原始數據披露：</strong></p><ul><li>FinMind <code>financial</code> 損益表：2024年停業單位損益（IncomeLossFromDiscontinuedOperation）=-7,287,000</li><li>FinMind <code>financial</code>：2025年停業單位損益=0（處分完成，無後續影響）</li><li>其他收益及費損淨額（OTHNOE）：2023年=20,618,000；2024年=13,963,000；2025年=15,830,000</li></ul><p><strong>分析：</strong> 久元於2024年處分重要子公司「廈門久元電子有限公司」股權，此為PCB檢測設備產業鏈中中國市場的重要佈局。處分案對公司股東權益「無不利重大影響」（依MOPS公告）。停業單位損益-729萬僅佔全年淨利1.22億的0.6%，影響極微。</p><p>值得注意的是，處分案並未產生大額「處分資產利益」。若公司透過變賣子公司套現，現金流入應反映於投資活動現金流；但FinMind現金流量表未顯示2024年有異常龐大的投資活動現金流入（僅呈現購置固定資產的流出）。這暗示處分價格可能屬合理對價，非急迫性變賣。</p><p>2025年停業單位損益歸零，表示廈門久元的財務報表已完全併出，公司營運結構更聚焦台灣本土。</p><h3 id="二、戰略意圖判別-strategic-intent" tabindex="-1">二、戰略意圖判別（Strategic Intent） <a class="header-anchor" href="#二、戰略意圖判別-strategic-intent" aria-label="Permalink to &quot;二、戰略意圖判別（Strategic Intent）&quot;">​</a></h3><p><strong>原始數據披露：</strong></p><ul><li>FinMind <code>cash_flow</code>：取得不動產廠房設備（CapEx）2023年=-3.33億、2024年=-3.76億、2025年=-9.83億</li><li>FinMind <code>cash_flow</code>：營業活動淨現金流入 2023年=5.19億、2024年=7.22億、2025年=6.64億</li><li>FinMind <code>dividend</code>：現金股利 112年後半年度=4.0元、113年後半年度=4.0元</li></ul><p><strong>分析：</strong> 資本支出呈現「加速擴張」態勢。2025年Q3單季CapEx達8.88億、Q4單季9.83億，全年合計9.83億為2023年的2.95倍。此等規模的資本投入，明確指向：</p><ol><li><strong>產能擴張</strong>：配合AI伺服器PCB需求增長，擴充高階載板檢測設備產能</li><li><strong>技術升級</strong>：投入新一代檢測技術研發與量產線建置</li></ol><p>資金流向分析：</p><ul><li>營業活動現金流（CFO）三年均為正值且穩健（5.19-7.22億），顯示本業現金生成能力強</li><li>投資活動淨現金流為負（因CapEx增加），屬成長期公司典型特徵</li><li>籌資活動淨現金流：2023年=-8.33億（償債為主），2024年=-4.86億</li></ul><p>結論：公司處於「擴張策略」階段，非生存防禦。處分廈門久元是戰略收縮（聚焦高毛利台灣/海外市場），而非財務危機。</p><h3 id="三、資產結構變動-asset-efficiency" tabindex="-1">三、資產結構變動（Asset Efficiency） <a class="header-anchor" href="#三、資產結構變動-asset-efficiency" aria-label="Permalink to &quot;三、資產結構變動（Asset Efficiency）&quot;">​</a></h3><p><strong>原始數據披露：</strong></p><ul><li>FinMind <code>balance_sheet</code>：資產總額 2023年底=83.08億、2024年底=85.31億</li><li>不動產廠房設備（PPE）2023年底=22.25億、2024年底=21.62億</li><li>存貨 2023年底=9.90億、2024年底=13.76億</li></ul><p><strong>分析：</strong> 處分子公司後，久元的資產結構發生以下變化：</p><table tabindex="0"><thead><tr><th>項目</th><th>2023年底</th><th>2024年底</th><th>變動</th></tr></thead><tbody><tr><td>資產總額</td><td>83.08億</td><td>85.31億</td><td>+2.7%</td></tr><tr><td>PPE佔比</td><td>26.78%</td><td>25.35%</td><td>-1.43pp</td></tr><tr><td>存貨佔比</td><td>11.92%</td><td>16.14%</td><td>+4.22pp</td></tr><tr><td>現金佔比</td><td>31.78%</td><td>28.11%</td><td>-3.67pp</td></tr></tbody></table><p>PPE佔比微降，但存貨佔比上升4.22個百分點，反映公司為應對訂單成長而提前備料。資產週轉率需持續追蹤，若存貨持續膨脹可能成為隱憂。</p><h2 id="💡-專家評析" tabindex="-1">💡 專家評析 <a class="header-anchor" href="#💡-專家評析" aria-label="Permalink to &quot;💡 專家評析&quot;">​</a></h2><h3 id="正面訊號" tabindex="-1">正面訊號 <a class="header-anchor" href="#正面訊號" aria-label="Permalink to &quot;正面訊號&quot;">​</a></h3><ol><li><strong>處分影響輕微</strong>：廈門久元處分案對財報衝擊極小（-729萬/1.22億=0.6%），非「祖產求生」型變賣</li><li><strong>資本支出明確</strong>：9.83億CapEx投入台灣產能，資金流向清晰可追蹤</li><li><strong>本業現金流強健</strong>：CFO連續三年超過5億，不依賴外部融資維持營運</li></ol><h3 id="風險警訊" tabindex="-1">風險警訊 <a class="header-anchor" href="#風險警訊" aria-label="Permalink to &quot;風險警訊&quot;">​</a></h3><ol><li><strong>存貨膨脹</strong>：2024年底存貨達13.76億（佔營收14.9%），較2023年增加39%，需關注呆滯風險</li><li><strong>營收波動</strong>：2024年營收衰退21.2%（11.75億→9.26億），雖2025年復甦至11.83億，但成長動能尚未完全確認</li><li><strong>營業利益率承壓</strong>：從2023年的23.9%降至2025年的9.2%，顯示成本結構或定價權面臨挑戰</li></ol><h3 id="華爾街空頭視角" tabindex="-1">華爾街空頭視角 <a class="header-anchor" href="#華爾街空頭視角" aria-label="Permalink to &quot;華爾街空頭視角&quot;">​</a></h3><p>若2026年PCB檢測設備需求放緩，9.83億的CapEx可能成為沉沒成本。目前PPE帳面價值21.62億，若未來產能利用率不足，將面臨減損風險。投資人應密切追蹤2026年Q1-Q2的產能利用率與訂單能見度。</p><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li><code>數據採集器查詢</code>: <code>/Users/kaipro/.openclaw/skills/finmind/數據採集器.py finance 6261 2023-01-01 2026-04-24 --df</code>（科目：營業收入、營業利益、稅後淨利、停業單位損益、其他收益及費損）</li><li><code>數據採集器查詢</code>: <code>/Users/kaipro/.openclaw/skills/finmind/數據採集器.py cash_flow 6261 2023-01-01 2026-04-24 --df</code>（科目：取得不動產廠房設備、營業活動淨現金流入）</li><li><code>數據採集器查詢</code>: <code>/Users/kaipro/.openclaw/skills/finmind/數據採集器.py balance_sheet 6261 2023-01-01 2026-04-24 --df</code>（科目：資產總額、存貨、現金及約當現金）</li><li><code>數據採集器查詢</code>: <code>/Users/kaipro/.openclaw/skills/finmind/數據採集器.py dividend 6261 2023-01-01 2026-04-24 --df</code>（科目：現金股利）</li><li><code>MOPS公告</code>: 久元處分重要子公司廈門久元電子有限公司股權專案（Yahoo Finance轉載公告）</li><li><code>Web Search</code>: <code>6261 久元 廈門久元 處分 子公司 財報</code> → Yahoo Finance公告確認處分案</li></ul>',38)])])}const f=a(o,[["render",r]]);export{_ as __pageData,f as default};
